parameters.jsCode:
const items = $input.all();
const now = new Date();
const sixHoursAgo = new Date(now - 6 * 60 * 60 * 1000);

// Filter to recent items only, pick top 3
const recent = items
  .filter(item => {
    const pubDate = new Date(item.json.pubDate || item.json.isoDate || 0);
    return pubDate > sixHoursAgo;
  })
  .slice(0, 3);

if (recent.length === 0) {
  // If no recent, take the latest item
  return [items[0]];
}

// Return first item for posting
const item = recent[0].json;
return [{
  json: {
    title: item.title || '',
    link: item.link || '',
    summary: (item.contentSnippet || item.content || item.summary || '').substring(0, 500),
    pubDate: item.pubDate || item.isoDate || '',
    author: item.creator || item.author || '',
    categories: (item.categories || []).join(', ')
  }
}];

const article = $('Code - Filter Recent Articles').first().json;
const aiRaw = $input.first().json.message?.content || '{}';

let posts;
try {
  posts = JSON.parse(aiRaw);
} catch (e) {
  posts = { twitter: article.title.substring(0, 250), linkedin: article.title + '\n\n' + article.summary };
}

const tweetText = (posts.twitter || article.title).substring(0, 270) + '\n\n' + article.link;
const linkedinText = (posts.linkedin || article.title + '\n\n' + article.summary) + '\n\n🔗 ' + article.link;

return [{
  json: {
    tweetText,
    linkedinText,
    hashtags: posts.hashtags || [],
    articleTitle: article.title,
    articleLink: article.link
  }
}];

